    pub fn main() -> i32 {
        match run() {
            Ok(code) => code,
            Err(error) => {
                eprintln!("hftbt bootstrap error: {error}");
                1
            }
        }
    }

    fn run() -> Result<i32, String> {
        let mut args: Vec<String> = env::args().skip(1).collect();
        let source_override = take_path_option(&mut args, "--source")?;
        if is_global_help(&args) {
            print_help();
            return Ok(0);
        }

        let source = source_override.unwrap_or(default_source()?);
        let harness = ensure_harness(&source)?;
        let command = if args.is_empty() {
            "verify".to_string()
        } else {
            args.remove(0)
        };

        match command.as_str() {
            "harness" => {
                println!("{}", harness.display());
                Ok(0)
            }
            "portable-proof" | "single-file-proof" | "e2e-proof" | "proof"
            | "proof-single-file" => run_portable_proof(&source, &args),
            "fmt" => run_cargo(&harness, &["fmt", "--all", "--", "--check"], &args),
            "check" => run_cargo(&harness, &["check", "--workspace", "--all-targets"], &args),
            "test" => run_cargo(&harness, &["test", "--workspace", "--all-targets"], &args),
            "doctest" | "doc-test" => {
                run_cargo(&harness, &["test", "-p", "hftbacktest", "--doc"], &args)
            }
            "build" => run_cargo(&harness, &["build", "--workspace"], &args),
            "release" => run_cargo(&harness, &["build", "--workspace", "--release"], &args),
            "py" | "build-py" => run_cargo(&harness, &["build", "-p", "py-hftbacktest"], &args),
            "auto"
            | "backtest-auto"
            | "binance-auto"
            | "binance-auto-backtest"
            | "binance-futures-auto" => run_binance_auto(&args),
            "binance-futures-db" | "binance-db" => {
                run_python_script("binance-futures-db", BINANCE_FUTURES_DB_PY, &args)
            }
            "binance-futures-convert" | "binance-convert" | "binance-npz" => {
                run_python_script("binance-futures-convert", BINANCE_FUTURES_CONVERT_PY, &args)
            }
            "binance-futures-l1-prepare"
            | "binance-l1-prepare"
            | "binance-bookticker"
            | "binance-bbo"
            | "binance-l1" => run_python_script(
                "binance-futures-l1-prepare",
                BINANCE_FUTURES_L1_PREPARE_PY,
                &args,
            ),
            "binance-futures-l2-prepare"
            | "binance-l2-prepare"
            | "binance-depth-prepare"
            | "binance-l2" => run_python_script(
                "binance-futures-l2-prepare",
                BINANCE_FUTURES_L2_PREPARE_PY,
                &args,
            ),
            "binance-futures-tick-l2"
            | "binance-tick-l2"
            | "binance-flow-l2"
            | "binance-synthetic-l2" => {
                run_python_script("binance-futures-tick-l2", BINANCE_FUTURES_TICK_L2_PY, &args)
            }
            "binance-vector-backtest" | "binance-backtest-report" | "binance-report" => {
                run_python_script("binance-vector-backtest", BINANCE_VECTOR_BACKTEST_PY, &args)
            }
            "pretrain"
            | "pre-train"
            | "pretrains"
            | "pre-trains"
            | "pre-trans"
            | "binance-pretrain"
            | "binance-pre-train"
            | "binance-futures-pretrain"
            | "binance-pretrain-dataset" => {
                run_python_script("binance-pretrain", BINANCE_PRETRAIN_PY, &args)
            }
            "production-pretrain"
            | "pretrain-e2e"
            | "production-pretrain-e2e"
            | "binance-pretrain-e2e"
            | "binance-production-pretrain"
            | "binance-production-pretrain-e2e" => run_python_script(
                "binance-production-pretrain-e2e",
                BINANCE_PRODUCTION_PRETRAIN_E2E_PY,
                &args,
            ),
            "train"
            | "neural-train"
            | "pretrain-train"
            | "pre-train-loop"
            | "binance-train"
            | "binance-neural-train"
            | "binance-pretrain-train"
            | "binance-full-neural-train" => {
                run_python_script("binance-neural-train", BINANCE_NEURAL_TRAIN_PY, &args)
            }
            "aga"
            | "aga-sample"
            | "aga-prepare"
            | "aga-train"
            | "aga-infer"
            | "aga-backtest"
            | "aga-audit"
            | "aga-auto"
            | "aga-proof"
            | "aga-lobster-convert"
            | "aga-lobframe-convert" => run_embedded_aga_stack(command.as_str(), &args),
            "binance-vectorization-audit" | "binance-vector-audit" | "binance-vectorization" => {
                run_python_script(
                    "binance-vectorization-audit",
                    BINANCE_VECTORIZATION_AUDIT_PY,
                    &args,
                )
            }
            "binance-lifecycle-audit"
            | "binance-order-lifecycle-audit"
            | "binance-correctness-audit"
            | "hft-lifecycle-audit" => {
                run_python_script("binance-lifecycle-audit", BINANCE_LIFECYCLE_AUDIT_PY, &args)
            }
            "binance-data-tiers" | "binance-tiers" | "binance-production-data" => {
                run_python_script("binance-data-tiers", BINANCE_DATA_TIERS_PY, &args)
            }
            "binance-futures-smoke" | "binance-smoke" | "binance-backtest-smoke" => run_cargo(
                &harness,
                &[
                    "run",
                    "-p",
                    "hftbacktest",
                    "--example",
                    "binance_npz_smoke",
                    "--",
                ],
                &args,
            ),
            "binance-futures-l2-smoke" | "binance-l2-smoke" | "binance-depth-smoke" => run_cargo(
                &harness,
                &[
                    "run",
                    "-p",
                    "hftbacktest",
                    "--example",
                    "binance_npz_smoke",
                    "--",
                    "--l2",
                ],
                &args,
            ),
            "binance-futures-l1-smoke" | "binance-l1-smoke" | "binance-bbo-smoke" => run_cargo(
                &harness,
                &[
                    "run",
                    "-p",
                    "hftbacktest",
                    "--example",
                    "binance_npz_smoke",
                    "--",
                    "--l1",
                ],
                &args,
            ),
            "collector" | "run-collector" => {
                run_cargo(&harness, &["run", "-p", "collector", "--"], &args)
            }
            "connector" | "run-connector" => {
                run_cargo(&harness, &["run", "-p", "connector", "--"], &args)
            }
            "clean" => run_cargo(&harness, &["clean"], &args),
            "verify" => run_verify(&harness),
            other => Err(format!(
                "unknown command `{other}`. Run `hftbt --help` for available commands."
            )),
        }
    }

    fn is_global_help(args: &[String]) -> bool {
        matches!(
            args.first().map(String::as_str),
            Some("-h" | "--help" | "help")
        )
    }

    fn print_help() {
        println!(
            "\
hftbt single-file bootstrap

Usage:
  rustc --edition=2024 hftbt.rs -o /tmp/hftbt
  /tmp/hftbt [--source PATH] <command>

Commands:
  verify        Run fmt, check, tests, and doctests
  fmt           Run cargo fmt --all -- --check
  check         Run cargo check --workspace --all-targets
  test          Run cargo test --workspace --all-targets
  doctest       Run cargo test -p hftbacktest --doc
  build         Run cargo build --workspace
  release       Run cargo build --workspace --release
  build-py      Build the Python extension crate
  portable-proof
                Prove hftbt.rs works from a new single-file folder and optional
                Binance sample e2e backtest
  binance-auto  End-to-end Binance USD-M data load, convert, L2 audit, optional
                synthetic L2, and multi-agent backtest report
  binance-db    Build an offline Binance USD-M Futures raw database
  binance-convert
                Convert Binance aggTrades raw archives to hftbacktest .npz
  binance-l1-prepare
                Convert Binance bookTicker archives to L1/BBO hftbacktest .npz
  binance-l2-prepare
                Audit/convert L2 websocket depth streams for hftbacktest replay
  binance-tick-l2
                Build synthetic L2 proxy depth from Binance aggTrades tick flow
  binance-report
                Run vectorized multi-agent multi-asset backtest and write a report
  binance-pretrain
                Build vectorized multi-asset pretraining tensors, labels, sample
                windows, QC report, and manifest; this is not a backtest
  binance-production-pretrain-e2e
                Run production E2E pretrain CLI: dataset build, neural training,
                strict QC gates, tee logs, model card, and summary manifest
  binance-neural-train
                Train real neural weights from pretraining tensors with NumPy
                backprop, Adam, multi-head losses, QC report, and checkpoints
  aga-prepare   Build Rust-native LOBFrame-equivalent feature frame from tick CSV
  aga-train     Train Rust-lite AGA linear-head metadata over feature rows
  aga-infer     Run embedded Rust AGA-Neural-HMM inference
  aga-backtest  Run embedded Rust AGA signal policy and backtest report
  aga-audit     Audit embedded Rust AGA signal output
  aga-auto      Run embedded Rust AGA sample -> inference -> audit -> backtest
  aga-proof     Compile/run embedded AGA proof from this single file
  binance-vectorization-audit
                Audit system-wide vectorization coverage and write a manifest
  binance-lifecycle-audit
                Audit Binance Futures order/accounting lifecycle invariants
  binance-data-tiers
                Write production L1/L2/L3 readiness manifest and checklist
  binance-smoke Verify a converted .npz with hftbacktest's Rust reader
  binance-l2-smoke
                Verify an L2 converted .npz with hftbacktest's Rust reader
  binance-l1-smoke
                Verify an L1/BBO converted .npz with hftbacktest's Rust reader
  collector     Run the collector binary; following args go to collector
  connector     Run the connector binary; following args go to connector
  harness       Print the generated external Cargo harness path
  clean         Run cargo clean in the external harness

Environment:
  HFTBT_SOURCE   Path to this hftbt.rs file
  HFTBT_HARNESS  External Cargo harness directory
"
        );
    }

