#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum TradeSignal {
    Buy,
    Sell,
    Hold,
    Cancel,
}

impl TradeSignal {
    fn as_str(self) -> &'static str {
        match self {
            Self::Buy => "Buy",
            Self::Sell => "Sell",
            Self::Hold => "Hold",
            Self::Cancel => "Cancel",
        }
    }

    fn from_str(value: &str) -> Self {
        match value.trim() {
            "Buy" | "BUY" | "buy" => Self::Buy,
            "Sell" | "SELL" | "sell" => Self::Sell,
            "Cancel" | "CANCEL" | "cancel" => Self::Cancel,
            _ => Self::Hold,
        }
    }
}

#[derive(Clone, Copy, Debug)]
struct ExecutionDecision {
    signal: TradeSignal,
    quote_width_bps: f64,
    order_size: f64,
    high_vol_prob: f64,
}

struct FeatureBuilder {
    lookback: usize,
    mids: VecDeque<f64>,
    ts: VecDeque<i64>,
    last_tick: Option<LobTick>,
    event_count: usize,
}

impl FeatureBuilder {
    fn new(lookback: usize) -> Self {
        Self {
            lookback,
            mids: VecDeque::with_capacity(lookback + 1),
            ts: VecDeque::with_capacity(lookback + 1),
            last_tick: None,
            event_count: 0,
        }
    }

    fn update(&mut self, tick: LobTick, label: i8) -> FeatureRow {
        let mid = 0.5 * (tick.bid_px + tick.ask_px);
        let spread = (tick.ask_px - tick.bid_px).max(0.0);
        let depth = (tick.bid_qty + tick.ask_qty).max(1e-12);
        let imbalance = (tick.bid_qty - tick.ask_qty) / depth;
        let micro = (tick.ask_px * tick.bid_qty + tick.bid_px * tick.ask_qty) / depth;
        let mid_ret_bps = match self.mids.back().copied() {
            Some(prev) if prev > 0.0 && mid > 0.0 => (mid / prev).ln() * 10_000.0,
            _ => 0.0,
        };
        let spread_bps = if mid > 0.0 {
            spread / mid * 10_000.0
        } else {
            0.0
        };
        let micro_bps = if mid > 0.0 {
            (micro - mid) / mid * 10_000.0
        } else {
            0.0
        };
        let ofi = self.ofi(tick);

        self.mids.push_back(mid);
        self.ts.push_back(tick.ts_ns);
        while self.mids.len() > self.lookback {
            self.mids.pop_front();
            self.ts.pop_front();
        }
        self.last_tick = Some(tick);
        self.event_count += 1;

        let sigma = realized_vol_bps(&self.mids) as f32;
        let lambda = self.event_rate() as f32;
        let trade_sign = tick.trade_side as f32;
        let trade_qty_norm = (tick.trade_qty / depth).clamp(0.0, 10.0) as f32;

        let x = vec![
            spread_bps as f32,
            mid_ret_bps as f32,
            imbalance as f32,
            (tick.bid_qty + 1.0).ln() as f32,
            (tick.ask_qty + 1.0).ln() as f32,
            (depth + 1.0).ln() as f32,
            micro_bps as f32,
            ofi as f32,
            trade_sign,
            trade_qty_norm,
            sigma,
            lambda,
        ];

        FeatureRow {
            ts_ns: tick.ts_ns,
            x,
            mid,
            label,
            sigma,
            lambda,
            ofi,
        }
    }

    fn ofi(&self, tick: LobTick) -> f32 {
        let Some(prev) = self.last_tick else {
            return 0.0;
        };
        let ask_of = if tick.ask_px > prev.ask_px {
            -prev.ask_qty
        } else if (tick.ask_px - prev.ask_px).abs() < f64::EPSILON {
            tick.ask_qty - prev.ask_qty
        } else {
            tick.ask_qty
        };
        let bid_of = if tick.bid_px < prev.bid_px {
            -prev.bid_qty
        } else if (tick.bid_px - prev.bid_px).abs() < f64::EPSILON {
            tick.bid_qty - prev.bid_qty
        } else {
            tick.bid_qty
        };
        let depth = (tick.bid_qty + tick.ask_qty + prev.bid_qty + prev.ask_qty).max(1e-12);
        ((bid_of - ask_of) / depth).clamp(-10.0, 10.0) as f32
    }

    fn event_rate(&self) -> f64 {
        if self.ts.len() < 2 {
            return 0.0;
        }
        let first = *self.ts.front().unwrap();
        let last = *self.ts.back().unwrap();
        let dt = ((last - first) as f64 / 1_000_000_000.0).max(1e-9);
        self.ts.len() as f64 / dt
    }
}


#[derive(Clone, Debug)]
struct TrainLiteResult {
    weights: Vec<f32>,
    bias: [f32; 3],
    mean: Vec<f32>,
    std: Vec<f32>,
    loss_initial: f64,
    loss_final: f64,
    accuracy: f64,
    epochs: usize,
    lr: f32,
}

fn feature_rows_from_ticks(ticks: &[LobTick], cfg: &AgaConfig) -> Vec<FeatureRow> {
    let labels = labels_from_ticks(ticks, cfg.horizon_rows, cfg.neutral_band_bps);
    let mut fb = FeatureBuilder::new(cfg.lookback);
    let mut rows = Vec::with_capacity(ticks.len());
    for (idx, tick) in ticks.iter().copied().enumerate() {
        rows.push(fb.update(tick, labels[idx]));
    }
    rows
}

fn write_feature_csv(rows: &[FeatureRow], path: &str) -> Result<(), String> {
    let mut f = File::create(path).map_err(|e| format!("failed to create {path}: {e}"))?;
    write!(f, "ts_ns,mid,label,sigma,lambda,ofi").map_err(|e| e.to_string())?;
    let dim = rows.first().map(|row| row.x.len()).unwrap_or(0);
    for i in 0..dim {
        write!(f, ",x{i}").map_err(|e| e.to_string())?;
    }
    writeln!(f).map_err(|e| e.to_string())?;
    for row in rows {
        write!(
            f,
            "{},{:.10},{},{:.8},{:.8},{:.8}",
            row.ts_ns, row.mid, row.label, row.sigma, row.lambda, row.ofi
        )
        .map_err(|e| e.to_string())?;
        for value in &row.x {
            write!(f, ",{:.8}", value).map_err(|e| e.to_string())?;
        }
        writeln!(f).map_err(|e| e.to_string())?;
    }
    Ok(())
}

fn train_lite_linear_head(rows: &[FeatureRow], obs_dim: usize, epochs: usize, lr: f32) -> TrainLiteResult {
    let n = rows.len().max(1) as f32;
    let mut mean = vec![0.0f32; obs_dim];
    let mut std = vec![0.0f32; obs_dim];
    for row in rows {
        for d in 0..obs_dim.min(row.x.len()) {
            mean[d] += row.x[d] / n;
        }
    }
    for row in rows {
        for d in 0..obs_dim.min(row.x.len()) {
            let z = row.x[d] - mean[d];
            std[d] += z * z / n;
        }
    }
    for value in &mut std {
        *value = value.sqrt().max(1e-6);
    }
    let mut weights = vec![0.0f32; 3 * obs_dim];
    let mut bias = [0.0f32; 3];
    let loss_initial = linear_head_loss(rows, obs_dim, &weights, &bias, &mean, &std);
    for _ in 0..epochs {
        for row in rows {
            let label = label_to_class(row.label);
            let probs = linear_head_probs(row, obs_dim, &weights, &bias, &mean, &std);
            for cls in 0..3 {
                let grad = probs[cls] - if cls == label { 1.0 } else { 0.0 };
                bias[cls] -= lr * grad;
                for d in 0..obs_dim.min(row.x.len()) {
                    let x = (row.x[d] - mean[d]) / std[d];
                    weights[cls * obs_dim + d] -= lr * grad * x;
                }
            }
        }
    }
    let loss_final = linear_head_loss(rows, obs_dim, &weights, &bias, &mean, &std);
    let accuracy = linear_head_accuracy(rows, obs_dim, &weights, &bias, &mean, &std);
    TrainLiteResult { weights, bias, mean, std, loss_initial, loss_final, accuracy, epochs, lr }
}

fn linear_head_probs(row: &FeatureRow, obs_dim: usize, weights: &[f32], bias: &[f32; 3], mean: &[f32], std: &[f32]) -> Vec<f32> {
    let mut logits = vec![0.0f32; 3];
    for cls in 0..3 {
        logits[cls] = bias[cls];
        for d in 0..obs_dim.min(row.x.len()) {
            logits[cls] += weights[cls * obs_dim + d] * ((row.x[d] - mean[d]) / std[d]);
        }
    }
    softmax(&logits)
}

fn linear_head_loss(rows: &[FeatureRow], obs_dim: usize, weights: &[f32], bias: &[f32; 3], mean: &[f32], std: &[f32]) -> f64 {
    if rows.is_empty() {
        return 0.0;
    }
    let mut loss = 0.0;
    for row in rows {
        let probs = linear_head_probs(row, obs_dim, weights, bias, mean, std);
        let label = label_to_class(row.label);
        loss -= (probs[label].max(1e-9)).ln() as f64;
    }
    loss / rows.len() as f64
}

fn linear_head_accuracy(rows: &[FeatureRow], obs_dim: usize, weights: &[f32], bias: &[f32; 3], mean: &[f32], std: &[f32]) -> f64 {
    if rows.is_empty() {
        return 0.0;
    }
    let mut correct = 0usize;
    for row in rows {
        let probs = linear_head_probs(row, obs_dim, weights, bias, mean, std);
        if argmax(&probs) == label_to_class(row.label) {
            correct += 1;
        }
    }
    correct as f64 / rows.len() as f64
}

fn label_to_class(label: i8) -> usize {
    match label {
        -1 => 0,
        1 => 2,
        _ => 1,
    }
}

fn write_train_lite_json(result: &TrainLiteResult, cfg: &AgaConfig, rows: usize, path: &str) -> Result<(), String> {
    let mut f = File::create(path).map_err(|e| format!("failed to create {path}: {e}"))?;
    writeln!(f, "{{").map_err(|e| e.to_string())?;
    writeln!(f, "  \"schema\": \"hftbt.aga_train_lite.v1\",").map_err(|e| e.to_string())?;
    writeln!(f, "  \"status\": \"PASS\",").map_err(|e| e.to_string())?;
    writeln!(f, "  \"rows\": {rows},").map_err(|e| e.to_string())?;
    writeln!(f, "  \"obs_dim\": {},", cfg.obs_dim).map_err(|e| e.to_string())?;
    writeln!(f, "  \"ctx_dim\": {},", cfg.ctx_dim).map_err(|e| e.to_string())?;
    writeln!(f, "  \"states\": {},", cfg.num_states).map_err(|e| e.to_string())?;
    writeln!(f, "  \"epochs\": {},", result.epochs).map_err(|e| e.to_string())?;
    writeln!(f, "  \"lr\": {:.8},", result.lr).map_err(|e| e.to_string())?;
    writeln!(f, "  \"loss_initial\": {:.10},", result.loss_initial).map_err(|e| e.to_string())?;
    writeln!(f, "  \"loss_final\": {:.10},", result.loss_final).map_err(|e| e.to_string())?;
    writeln!(f, "  \"accuracy\": {:.10},", result.accuracy).map_err(|e| e.to_string())?;
    writeln!(f, "  \"feature_mean\": {},", json_f32_array(&result.mean)).map_err(|e| e.to_string())?;
    writeln!(f, "  \"feature_std\": {},", json_f32_array(&result.std)).map_err(|e| e.to_string())?;
    writeln!(f, "  \"linear_head_weights\": {},", json_f32_array(&result.weights)).map_err(|e| e.to_string())?;
    writeln!(f, "  \"linear_head_bias\": {}", json_f32_array(&result.bias)).map_err(|e| e.to_string())?;
    writeln!(f, "}}").map_err(|e| e.to_string())?;
    Ok(())
}

fn json_f32_array(values: &[f32]) -> String {
    let mut out = String::from("[");
    for (idx, value) in values.iter().enumerate() {
        if idx > 0 {
            out.push(',');
        }
        out.push_str(&format!("{:.8}", value));
    }
    out.push(']');
    out
}

fn labels_from_ticks(ticks: &[LobTick], horizon_rows: usize, neutral_band_bps: f64) -> Vec<i8> {
    let mids: Vec<f64> = ticks.iter().map(|t| 0.5 * (t.bid_px + t.ask_px)).collect();
    let mut labels = vec![0i8; ticks.len()];
    for i in 0..ticks.len() {
        let j = (i + horizon_rows).min(ticks.len().saturating_sub(1));
        if mids[i] <= 0.0 || j == i {
            labels[i] = 0;
            continue;
        }
        let change_bps = (mids[j] / mids[i] - 1.0) * 10_000.0;
        labels[i] = if change_bps > neutral_band_bps {
            1
        } else if change_bps < -neutral_band_bps {
            -1
        } else {
            0
        };
    }
    labels
}

fn run_inference(ticks: &[LobTick], cfg: &AgaConfig) -> InferenceResult {
    let labels = labels_from_ticks(ticks, cfg.horizon_rows, cfg.neutral_band_bps);
    let mut fb = FeatureBuilder::new(cfg.lookback);
    let mut model = AgaHftModel::new(cfg);
    let mut rows = Vec::with_capacity(ticks.len());
    let mut feature_summary = FeatureSummary::default();
    let mut gate_sum = 0.0;
    let mut confidence_sum = 0.0;
    let mut entropy_sum = 0.0;
    let mut regime_counts = BTreeMap::new();

    for (idx, tick) in ticks.iter().copied().enumerate() {
        let row = fb.update(tick, labels[idx]);
        let out = model.step(&row);
        let dec = policy(&out, cfg);
        let mid = row.mid.max(1e-12);
        feature_summary.rows += 1;
        feature_summary.avg_spread_bps += (tick.ask_px - tick.bid_px).max(0.0) / mid * 10_000.0;
        feature_summary.avg_abs_imbalance += row.x[2].abs() as f64;
        feature_summary.avg_abs_ofi += row.ofi.abs() as f64;
        feature_summary.avg_sigma += row.sigma as f64;
        feature_summary.avg_lambda += row.lambda as f64;
        gate_sum += out.gate_mean as f64;
        confidence_sum += out.confidence as f64;
        entropy_sum += entropy(&out.regime_prob);
        *regime_counts.entry(out.regime).or_insert(0usize) += 1;

        rows.push(SignalRow {
            ts_ns: out.ts_ns,
            prob_down: out.prob_down,
            prob_neutral: out.prob_neutral,
            prob_up: out.prob_up,
            regime: out.regime,
            gate_mean: out.gate_mean,
            confidence: out.confidence,
            label: row.label,
            signal: dec.signal,
            quote_width_bps: dec.quote_width_bps,
            order_size: dec.order_size,
            high_vol_prob: dec.high_vol_prob,
        });
    }

    let n = feature_summary.rows.max(1) as f64;
    feature_summary.avg_spread_bps /= n;
    feature_summary.avg_abs_imbalance /= n;
    feature_summary.avg_abs_ofi /= n;
    feature_summary.avg_sigma /= n;
    feature_summary.avg_lambda /= n;

    InferenceResult {
        rows,
        feature_summary,
        model_summary: ModelSummary {
            avg_gate: gate_sum / n,
            avg_confidence: confidence_sum / n,
            posterior_entropy: entropy_sum / n,
            regime_counts,
        },
    }
}

struct FineEncoder {
    obs_dim: usize,
    ctx_dim: usize,
    weights: Vec<f32>,
    bias: Vec<f32>,
    memory: VecDeque<Vec<f32>>,
}

impl FineEncoder {
    fn new(obs_dim: usize, ctx_dim: usize, lookback: usize) -> Self {
        Self {
            obs_dim,
            ctx_dim,
            weights: init_vec(ctx_dim * obs_dim * 3, 0.016),
            bias: vec![0.0; ctx_dim],
            memory: VecDeque::with_capacity(lookback + 1),
        }
    }

    fn step(&mut self, x: &[f32]) -> Vec<f32> {
        self.memory.push_back(x.to_vec());
        while self.memory.len() > 16 {
            self.memory.pop_front();
        }
        let dilations = [1usize, 2, 4];
        let mut h = vec![0.0; self.ctx_dim];
        for j in 0..self.ctx_dim {
            let mut y = self.bias[j];
            for (d_idx, dilation) in dilations.iter().enumerate() {
                let sample = self.memory.len().saturating_sub(*dilation);
                let source = self
                    .memory
                    .get(sample)
                    .unwrap_or_else(|| self.memory.back().unwrap());
                for i in 0..self.obs_dim {
                    let w_idx = (j * self.obs_dim * 3) + (d_idx * self.obs_dim) + i;
                    y += self.weights[w_idx] * source[i];
                }
            }
            h[j] = relu(y / dilations.len() as f32);
        }
        h
    }
}

struct CoarseEncoder {
    obs_dim: usize,
    ctx_dim: usize,
    state: Vec<f32>,
    fast: Vec<f32>,
    slow: Vec<f32>,
    weights: Vec<f32>,
}

impl CoarseEncoder {
    fn new(obs_dim: usize, ctx_dim: usize) -> Self {
        Self {
            obs_dim,
            ctx_dim,
            state: vec![0.0; ctx_dim],
            fast: vec![0.0; obs_dim],
            slow: vec![0.0; obs_dim],
            weights: init_vec(ctx_dim * obs_dim * 2, 0.010),
        }
    }

    fn step(&mut self, x: &[f32]) -> Vec<f32> {
        for i in 0..self.obs_dim {
            self.fast[i] = 0.80 * self.fast[i] + 0.20 * x[i];
            self.slow[i] = 0.97 * self.slow[i] + 0.03 * x[i];
        }
        for j in 0..self.ctx_dim {
            let mut y = 0.0;
            for i in 0..self.obs_dim {
                y += self.weights[j * self.obs_dim * 2 + i] * self.fast[i];
                y += self.weights[j * self.obs_dim * 2 + self.obs_dim + i]
                    * (self.fast[i] - self.slow[i]);
            }
            self.state[j] = 0.94 * self.state[j] + 0.06 * y.tanh();
        }
        self.state.clone()
    }
}

struct AdaptiveGate {
    ctx_dim: usize,
    w_sigma: Vec<f32>,
    w_lambda: Vec<f32>,
    w_ofi: Vec<f32>,
    bias: Vec<f32>,
    last_gate: Vec<f32>,
}

impl AdaptiveGate {
    fn new(ctx_dim: usize) -> Self {
        Self {
            ctx_dim,
            w_sigma: vec![0.030; ctx_dim],
            w_lambda: vec![0.002; ctx_dim],
            w_ofi: vec![0.20; ctx_dim],
            bias: vec![-0.15; ctx_dim],
            last_gate: vec![0.5; ctx_dim],
        }
    }

    fn fuse(
        &mut self,
        fine: &[f32],
        coarse: &[f32],
        sigma: f32,
        lambda: f32,
        ofi: f32,
    ) -> Vec<f32> {
        let mut out = vec![0.0; self.ctx_dim];
        for i in 0..self.ctx_dim {
            let g = sigmoid(
                self.bias[i]
                    + self.w_sigma[i] * sigma
                    + self.w_lambda[i] * lambda
                    + self.w_ofi[i] * ofi.abs(),
            );
            self.last_gate[i] = g;
            out[i] = g * fine[i] + (1.0 - g) * coarse[i];
        }
        out
    }

    fn gate_mean(&self) -> f32 {
        self.last_gate.iter().sum::<f32>() / self.last_gate.len().max(1) as f32
    }
}

struct CausalAttention {
    ctx_dim: usize,
    lookback: usize,
    memory: VecDeque<Vec<f32>>,
}

impl CausalAttention {
    fn new(ctx_dim: usize, lookback: usize) -> Self {
        Self {
            ctx_dim,
            lookback,
            memory: VecDeque::with_capacity(lookback + 1),
        }
    }

    fn step(&mut self, z: &[f32]) -> Vec<f32> {
        self.memory.push_back(z.to_vec());
        while self.memory.len() > self.lookback {
            self.memory.pop_front();
        }
        let scale = (self.ctx_dim as f32).sqrt().max(1.0);
        let scores: Vec<f32> = self
            .memory
            .iter()
            .map(|past| dot(z, past) / scale)
            .collect();
        let weights = softmax(&scores);
        let mut out = vec![0.0; self.ctx_dim];
        for (w, past) in weights.iter().zip(self.memory.iter()) {
            for i in 0..self.ctx_dim {
                out[i] += *w * past[i];
            }
        }
        out
    }
}

struct ConditionalAffineFlow {
    k: usize,
    obs_dim: usize,
    ctx_dim: usize,
    shift_w: Vec<f32>,
    scale_w: Vec<f32>,
    shift_b: Vec<f32>,
    scale_b: Vec<f32>,
}

impl ConditionalAffineFlow {
    fn new(k: usize, obs_dim: usize, ctx_dim: usize) -> Self {
        Self {
            k,
            obs_dim,
            ctx_dim,
            shift_w: init_vec(k * obs_dim * ctx_dim, 0.002),
            scale_w: init_vec(k * obs_dim * ctx_dim, 0.001),
            shift_b: vec![0.0; k * obs_dim],
            scale_b: vec![0.0; k * obs_dim],
        }
    }

    fn log_prob_by_state(&self, x: &[f32], c: &[f32]) -> Vec<f32> {
        let mut out = vec![0.0; self.k];
        for s in 0..self.k {
            let mut logp = 0.0;
            for d in 0..self.obs_dim {
                let shift = self.cond(&self.shift_w, &self.shift_b, s, d, c);
                let scale = self
                    .cond(&self.scale_w, &self.scale_b, s, d, c)
                    .clamp(-4.0, 4.0);
                let u = (x[d].clamp(-50.0, 50.0) - shift) * (-scale).exp();
                logp += -0.5 * u * u - scale - 0.918_938_5;
            }
            out[s] = logp;
        }
        out
    }

    fn cond(&self, w: &[f32], b: &[f32], s: usize, d: usize, c: &[f32]) -> f32 {
        let mut y = b[s * self.obs_dim + d];
        let base = (s * self.obs_dim + d) * self.ctx_dim;
        for i in 0..self.ctx_dim {
            y += w[base + i] * c[i];
        }
        y
    }
}

struct NeuralHmm {
    k: usize,
    ctx_dim: usize,
    log_alpha: Vec<f32>,
    trans_w: Vec<f32>,
    trans_b: Vec<f32>,
    alpha_vol: f32,
    initialized: bool,
}

impl NeuralHmm {
    fn new(k: usize, ctx_dim: usize) -> Self {
        Self {
            k,
            ctx_dim,
            log_alpha: vec![-(k as f32).ln(); k],
            trans_w: init_vec(k * k * ctx_dim, 0.0015),
            trans_b: (0..k * k)
                .map(|idx| if idx / k == idx % k { 0.20 } else { -0.05 })
                .collect(),
            alpha_vol: 0.035,
            initialized: false,
        }
    }

    fn transition_log_probs(&self, c: &[f32], sigma: f32) -> Vec<f32> {
        let mut out = vec![0.0; self.k * self.k];
        let tau = 1.0 + self.alpha_vol.abs() * sigma.max(0.0);
        for i in 0..self.k {
            let mut row = vec![0.0; self.k];
            for j in 0..self.k {
                let mut y = self.trans_b[i * self.k + j];
                for d in 0..self.ctx_dim {
                    y += self.trans_w[(i * self.k + j) * self.ctx_dim + d] * c[d];
                }
                row[j] = y / tau.max(1e-6);
            }
            let z = logsumexp(&row);
            for j in 0..self.k {
                out[i * self.k + j] = row[j] - z;
            }
        }
        out
    }

    fn forward_step(&mut self, log_emit: &[f32], log_a: &[f32]) -> Vec<f32> {
        if !self.initialized {
            for j in 0..self.k {
                self.log_alpha[j] = log_emit[j] - (self.k as f32).ln();
            }
            normalize_log_probs(&mut self.log_alpha);
            self.initialized = true;
            return self.posterior();
        }

        let mut next = vec![f32::NEG_INFINITY; self.k];
        for j in 0..self.k {
            let mut scores = vec![0.0; self.k];
            for i in 0..self.k {
                scores[i] = self.log_alpha[i] + log_a[i * self.k + j];
            }
            next[j] = log_emit[j] + logsumexp(&scores);
        }
        normalize_log_probs(&mut next);
        self.log_alpha = next;
        self.posterior()
    }

    fn posterior(&self) -> Vec<f32> {
        self.log_alpha.iter().map(|x| x.exp()).collect()
    }
}

struct ClassifierHead {
    ctx_dim: usize,
    k: usize,
    w: Vec<f32>,
    b: [f32; 3],
}

impl ClassifierHead {
    fn new(ctx_dim: usize, k: usize) -> Self {
        Self {
            ctx_dim,
            k,
            w: init_vec(3 * (ctx_dim + k), 0.010),
            b: [-0.05, 0.15, -0.05],
        }
    }

    fn forward(&self, c: &[f32], posterior: &[f32], x: &[f32]) -> [f32; 3] {
        let mut input = Vec::with_capacity(self.ctx_dim + self.k);
        input.extend_from_slice(c);
        input.extend_from_slice(posterior);
        let in_dim = input.len();
        let mut y = self.b;
        for cls in 0..3 {
            for i in 0..in_dim {
                y[cls] += self.w[cls * in_dim + i] * input[i];
            }
        }

        let imbalance = x.get(2).copied().unwrap_or(0.0);
        let micro = x.get(6).copied().unwrap_or(0.0) / 10.0;
        let ofi = x.get(7).copied().unwrap_or(0.0);
        let ret = x.get(1).copied().unwrap_or(0.0) / 20.0;
        let sigma = x.get(10).copied().unwrap_or(0.0);
        let directional = 1.20 * imbalance + 0.80 * ofi + 0.35 * micro + 0.12 * ret;
        y[2] += directional;
        y[0] -= directional;
        y[1] += 0.65 - directional.abs() - 0.005 * sigma;
        y
    }
}

struct AgaHftModel {
    fine: FineEncoder,
    coarse: CoarseEncoder,
    gate: AdaptiveGate,
    attn: CausalAttention,
    flow: ConditionalAffineFlow,
    hmm: NeuralHmm,
    head: ClassifierHead,
}

impl AgaHftModel {
    fn new(cfg: &AgaConfig) -> Self {
        Self {
            fine: FineEncoder::new(cfg.obs_dim, cfg.ctx_dim, cfg.lookback),
            coarse: CoarseEncoder::new(cfg.obs_dim, cfg.ctx_dim),
            gate: AdaptiveGate::new(cfg.ctx_dim),
            attn: CausalAttention::new(cfg.ctx_dim, cfg.lookback),
            flow: ConditionalAffineFlow::new(cfg.num_states, cfg.obs_dim, cfg.ctx_dim),
            hmm: NeuralHmm::new(cfg.num_states, cfg.ctx_dim),
            head: ClassifierHead::new(cfg.ctx_dim, cfg.num_states),
        }
    }

    fn step(&mut self, row: &FeatureRow) -> ModelOutput {
        let h_fine = self.fine.step(&row.x);
        let h_coarse = self.coarse.step(&row.x);
        let z = self
            .gate
            .fuse(&h_fine, &h_coarse, row.sigma, row.lambda, row.ofi);
        let c = self.attn.step(&z);
        let log_emit = self.flow.log_prob_by_state(&row.x, &c);
        let log_a = self.hmm.transition_log_probs(&c, row.sigma);
        let posterior = self.hmm.forward_step(&log_emit, &log_a);
        let logits = self.head.forward(&c, &posterior, &row.x);
        let probs = softmax(&logits);
        let regime = argmax(&posterior);
        let confidence = probs.iter().copied().fold(0.0, f32::max);
        ModelOutput {
            ts_ns: row.ts_ns,
            prob_down: probs[0],
            prob_neutral: probs[1],
            prob_up: probs[2],
            regime,
            regime_prob: posterior,
            gate_mean: self.gate.gate_mean(),
            confidence,
        }
    }
}

fn policy(out: &ModelOutput, cfg: &AgaConfig) -> ExecutionDecision {
    let high_vol_prob = out
        .regime_prob
        .get(
            cfg.high_vol_state
                .min(out.regime_prob.len().saturating_sub(1)),
        )
        .copied()
        .unwrap_or(0.0) as f64;
    let quote_width_bps = cfg.base_spread_bps * (1.0 + 2.25 * high_vol_prob);
    let order_size =
        cfg.base_order_size * out.confidence as f64 * (1.0 - 0.70 * high_vol_prob).clamp(0.0, 1.0);
    let signal = if high_vol_prob > 0.90 {
        TradeSignal::Cancel
    } else if out.confidence < cfg.min_confidence {
        TradeSignal::Hold
    } else if out.prob_up > cfg.buy_threshold && out.prob_up > out.prob_down {
        TradeSignal::Buy
    } else if out.prob_down > cfg.sell_threshold && out.prob_down > out.prob_up {
        TradeSignal::Sell
    } else {
        TradeSignal::Hold
    };
    ExecutionDecision {
        signal,
        quote_width_bps,
        order_size,
        high_vol_prob,
    }
}

#[derive(Clone, Debug, Default)]
struct BacktestMetrics {
    rows: usize,
    trades: usize,
    fills: usize,
    fill_ratio: f64,
    total_pnl: f64,
    total_fees: f64,
    equity_final: f64,
    sharpe: f64,
    sortino: f64,
    max_drawdown: f64,
    win_rate: f64,
    final_inventory: f64,
}

#[derive(Clone, Debug)]
struct BacktestReport {
    schema: String,
    version: String,
    metrics: BacktestMetrics,
    feature_summary: FeatureSummary,
    model_summary: ModelSummary,
    confusion: [[usize; 3]; 3],
    invariants: InvariantReport,
    config: BTreeMap<String, String>,
}

#[derive(Clone, Debug)]
struct InvariantReport {
    status: String,
    checks: Vec<InvariantCheck>,
}

#[derive(Clone, Debug)]
struct InvariantCheck {
    name: String,
    passed: bool,
    severity: String,
    detail: String,
}

fn run_backtest(
    ticks: &[LobTick],
    infer: &InferenceResult,
    cfg: &AgaConfig,
    bt_cfg: &BacktestConfig,
) -> BacktestReport {
    let mut cash = bt_cfg.initial_cash;
    let mut inventory = 0.0f64;
    let mut entry_price = 0.0f64;
    let mut realized = Vec::new();
    let mut equity_curve = Vec::with_capacity(ticks.len());
    let mut trades = 0usize;
    let mut fills = 0usize;
    let mut total_fees = 0.0;
    let mut confusion = [[0usize; 3]; 3];

    for i in 0..ticks.len() {
        let signal_idx = i.saturating_sub(bt_cfg.latency_rows);
        let row = &infer.rows[signal_idx];
        let tick = ticks[i];
        let mid = 0.5 * (tick.bid_px + tick.ask_px);
        let label_idx = match row.label {
            -1 => 0,
            0 => 1,
            1 => 2,
            _ => 1,
        };
        let pred_idx = match row.signal {
            TradeSignal::Sell => 0,
            TradeSignal::Hold | TradeSignal::Cancel => 1,
            TradeSignal::Buy => 2,
        };
        confusion[label_idx][pred_idx] += 1;

        if row.signal == TradeSignal::Cancel {
            equity_curve.push(cash + inventory * mid);
            continue;
        }

        let size = row.order_size.min(cfg.max_inventory).max(0.0);
        if size <= 0.0 {
            equity_curve.push(cash + inventory * mid);
            continue;
        }

        match row.signal {
            TradeSignal::Buy if inventory <= 0.0 => {
                if inventory < 0.0 {
                    let px = execution_price(tick, true, &bt_cfg.mode, bt_cfg.slippage_bps);
                    let pnl = (entry_price - px) * (-inventory);
                    let fee = fee(px, -inventory, bt_cfg.fee_bps);
                    cash += pnl - fee;
                    total_fees += fee;
                    realized.push(pnl - fee);
                    trades += 1;
                    fills += 1;
                }
                let px = execution_price(tick, true, &bt_cfg.mode, bt_cfg.slippage_bps);
                let fee = fee(px, size, bt_cfg.fee_bps);
                cash -= fee;
                total_fees += fee;
                inventory = size;
                entry_price = px;
                fills += 1;
            }
            TradeSignal::Sell if inventory >= 0.0 => {
                if inventory > 0.0 {
                    let px = execution_price(tick, false, &bt_cfg.mode, bt_cfg.slippage_bps);
                    let pnl = (px - entry_price) * inventory;
                    let fee = fee(px, inventory, bt_cfg.fee_bps);
                    cash += pnl - fee;
                    total_fees += fee;
                    realized.push(pnl - fee);
                    trades += 1;
                    fills += 1;
                }
                let px = execution_price(tick, false, &bt_cfg.mode, bt_cfg.slippage_bps);
                let fee = fee(px, size, bt_cfg.fee_bps);
                cash -= fee;
                total_fees += fee;
                inventory = -size;
                entry_price = px;
                fills += 1;
            }
            _ => {}
        }
        equity_curve.push(cash + inventory * mid);
    }

    if let (Some(last_tick), true) = (ticks.last().copied(), inventory.abs() > 0.0) {
        let mid = 0.5 * (last_tick.bid_px + last_tick.ask_px);
        let pnl = if inventory > 0.0 {
            (mid - entry_price) * inventory
        } else {
            (entry_price - mid) * (-inventory)
        };
        let fee = fee(mid, inventory.abs(), bt_cfg.fee_bps);
        cash += pnl - fee;
        total_fees += fee;
        realized.push(pnl - fee);
        trades += 1;
        inventory = 0.0;
        equity_curve.push(cash);
    }

    let equity_final = *equity_curve.last().unwrap_or(&cash);
    let total_pnl = equity_final - bt_cfg.initial_cash;
    let metrics = BacktestMetrics {
        rows: ticks.len(),
        trades,
        fills,
        fill_ratio: fills as f64
            / infer
                .rows
                .iter()
                .filter(|r| matches!(r.signal, TradeSignal::Buy | TradeSignal::Sell))
                .count()
                .max(1) as f64,
        total_pnl,
        total_fees,
        equity_final,
        sharpe: sharpe(&realized),
        sortino: sortino(&realized),
        max_drawdown: max_drawdown(&equity_curve),
        win_rate: realized.iter().filter(|x| **x > 0.0).count() as f64
            / realized.len().max(1) as f64,
        final_inventory: inventory,
    };

    let invariants = backtest_invariants(&metrics, infer, ticks);
    let mut config = BTreeMap::new();
    config.insert(
        "model".to_string(),
        "LOBFrame+AGA+NeuralHMM+ZukoLite".to_string(),
    );
    config.insert("fee_bps".to_string(), format!("{:.6}", bt_cfg.fee_bps));
    config.insert(
        "slippage_bps".to_string(),
        format!("{:.6}", bt_cfg.slippage_bps),
    );
    config.insert("latency_rows".to_string(), bt_cfg.latency_rows.to_string());
    config.insert("mode".to_string(), bt_cfg.mode.clone());
    config.insert("lookback".to_string(), cfg.lookback.to_string());
    config.insert("horizon_rows".to_string(), cfg.horizon_rows.to_string());

    BacktestReport {
        schema: "lobframe.hftbt.backtest.v1".to_string(),
        version: VERSION.to_string(),
        metrics,
        feature_summary: infer.feature_summary.clone(),
        model_summary: infer.model_summary.clone(),
        confusion,
        invariants,
        config,
    }
}

fn execution_price(tick: LobTick, buy: bool, mode: &str, slippage_bps: f64) -> f64 {
    let mid = 0.5 * (tick.bid_px + tick.ask_px);
    let base = match mode {
        "mid" => mid,
        "limit" => {
            if buy {
                tick.bid_px
            } else {
                tick.ask_px
            }
        }
        _ => {
            if buy {
                tick.ask_px
            } else {
                tick.bid_px
            }
        }
    };
    let slip = base * slippage_bps / 10_000.0;
    if buy {
        base + slip
    } else {
        base - slip
    }
}

fn fee(price: f64, qty: f64, fee_bps: f64) -> f64 {
    price.abs() * qty.abs() * fee_bps / 10_000.0
}

fn backtest_invariants(
    metrics: &BacktestMetrics,
    infer: &InferenceResult,
    ticks: &[LobTick],
) -> InvariantReport {
    let mut checks = Vec::new();
    push_check(
        &mut checks,
        "rows_match",
        metrics.rows == infer.rows.len() && metrics.rows == ticks.len(),
        "ERROR",
        format!("ticks={} signals={}", ticks.len(), infer.rows.len()),
    );
    push_check(
        &mut checks,
        "finite_pnl",
        metrics.total_pnl.is_finite() && metrics.equity_final.is_finite(),
        "ERROR",
        format!("pnl={:.6}", metrics.total_pnl),
    );
    push_check(
        &mut checks,
        "inventory_flat_at_end",
        metrics.final_inventory.abs() < 1e-12,
        "ERROR",
        format!("final_inventory={:.6}", metrics.final_inventory),
    );
    push_check(
        &mut checks,
        "probabilities_valid",
        infer.rows.iter().all(prob_row_ok),
        "ERROR",
        "all probabilities finite and sum to one".to_string(),
    );
    push_check(
        &mut checks,
        "timestamps_monotonic",
        infer.rows.windows(2).all(|w| w[1].ts_ns >= w[0].ts_ns),
        "ERROR",
        "signal timestamps monotonic".to_string(),
    );
    let status = if checks.iter().any(|c| !c.passed && c.severity == "ERROR") {
        "FAIL"
    } else {
        "PASS"
    };
    InvariantReport {
        status: status.to_string(),
        checks,
    }
}

fn push_check(
    checks: &mut Vec<InvariantCheck>,
    name: &str,
    passed: bool,
    severity: &str,
    detail: String,
) {
    checks.push(InvariantCheck {
        name: name.to_string(),
        passed,
        severity: if passed {
            "INFO".to_string()
        } else {
            severity.to_string()
        },
        detail,
    });
}

#[derive(Clone, Debug)]
struct SignalAudit {
    status: String,
    rows: usize,
    timestamp_monotonic: bool,
    probability_sum_ok: bool,
    finite: bool,
    avg_gate: f64,
    avg_confidence: f64,
    min_confidence: f64,
    max_confidence: f64,
    signal_counts: BTreeMap<String, usize>,
}

fn audit_signals(rows: &[SignalRow]) -> SignalAudit {
    let timestamp_monotonic = rows.windows(2).all(|w| w[1].ts_ns >= w[0].ts_ns);
    let probability_sum_ok = rows.iter().all(prob_row_ok);
    let finite = rows.iter().all(|r| {
        r.gate_mean.is_finite()
            && r.confidence.is_finite()
            && r.quote_width_bps.is_finite()
            && r.order_size.is_finite()
    });
    let mut signal_counts = BTreeMap::new();
    let mut gate_sum = 0.0;
    let mut conf_sum = 0.0;
    let mut min_conf = f64::INFINITY;
    let mut max_conf = f64::NEG_INFINITY;
    for row in rows {
        *signal_counts
            .entry(row.signal.as_str().to_string())
            .or_insert(0) += 1;
        gate_sum += row.gate_mean as f64;
        conf_sum += row.confidence as f64;
        min_conf = min_conf.min(row.confidence as f64);
        max_conf = max_conf.max(row.confidence as f64);
    }
    let n = rows.len().max(1) as f64;
    let passed = !rows.is_empty() && timestamp_monotonic && probability_sum_ok && finite;
    SignalAudit {
        status: if passed { "PASS" } else { "FAIL" }.to_string(),
        rows: rows.len(),
        timestamp_monotonic,
        probability_sum_ok,
        finite,
        avg_gate: gate_sum / n,
        avg_confidence: conf_sum / n,
        min_confidence: if min_conf.is_finite() { min_conf } else { 0.0 },
        max_confidence: if max_conf.is_finite() { max_conf } else { 0.0 },
        signal_counts,
    }
}

fn prob_row_ok(row: &SignalRow) -> bool {
    let sum = row.prob_down + row.prob_neutral + row.prob_up;
    row.prob_down.is_finite()
        && row.prob_neutral.is_finite()
        && row.prob_up.is_finite()
        && (sum - 1.0).abs() < 1e-3
        && row.prob_down >= -1e-6
        && row.prob_neutral >= -1e-6
        && row.prob_up >= -1e-6
}

fn generate_sample_ticks(rows: usize, seed: u64) -> Vec<LobTick> {
    let mut rng = XorShift64::new(seed);
    let mut out = Vec::with_capacity(rows);
    let mut mid = 100.0;
    let mut imbalance_state = 0.0;
    for i in 0..rows {
        let shock = rng.normalish() * 0.010;
        imbalance_state = 0.96 * imbalance_state + 0.04 * rng.normalish();
        mid += shock + imbalance_state * 0.006;
        if i % 900 == 0 && i > 0 {
            mid += rng.normalish() * 0.20;
        }
        mid = mid.max(1.0);
        let spread = 0.01 + 0.02 * rng.next_f64();
        let bid_qty =
            (8.0 + 5.0 * (1.0 + imbalance_state).max(0.05) + rng.next_f64() * 4.0).max(0.1);
        let ask_qty =
            (8.0 + 5.0 * (1.0 - imbalance_state).max(0.05) + rng.next_f64() * 4.0).max(0.1);
        let trade_side = if rng.next_f64() + imbalance_state * 0.15 > 0.5 {
            1
        } else {
            -1
        };
        let trade_qty = 0.05 + rng.next_f64() * 0.8;
        out.push(LobTick {
            ts_ns: 1_700_000_000_000_000_000 + i as i64 * 1_000_000,
            bid_px: mid - spread * 0.5,
            ask_px: mid + spread * 0.5,
            bid_qty,
            ask_qty,
            trade_px: mid,
            trade_qty,
            trade_side,
        });
    }
    out
}

fn read_ticks_csv(path: &str, max_rows: usize) -> Result<Vec<LobTick>, String> {
    let file = File::open(path).map_err(|e| format!("failed to open {path}: {e}"))?;
    let mut out = Vec::new();
    for (line_no, line) in BufReader::new(file).lines().enumerate() {
        let line = line.map_err(|e| e.to_string())?;
        if line.trim().is_empty() || line.starts_with("ts") {
            continue;
        }
        let cols = split_csv_simple(&line);
        if cols.len() < 8 {
            return Err(format!(
                "{path}:{} expected 8 columns, got {}",
                line_no + 1,
                cols.len()
            ));
        }
        out.push(LobTick {
            ts_ns: parse_cell(&cols[0], "ts_ns")?,
            bid_px: parse_cell(&cols[1], "bid_px")?,
            ask_px: parse_cell(&cols[2], "ask_px")?,
            bid_qty: parse_cell(&cols[3], "bid_qty")?,
            ask_qty: parse_cell(&cols[4], "ask_qty")?,
            trade_px: parse_cell(&cols[5], "trade_px")?,
            trade_qty: parse_cell(&cols[6], "trade_qty")?,
            trade_side: parse_cell(&cols[7], "trade_side")?,
        });
        if out.len() >= max_rows {
            break;
        }
    }
    Ok(out)
}

fn write_ticks_csv(ticks: &[LobTick], path: &str) -> Result<(), String> {
    let mut f = File::create(path).map_err(|e| format!("failed to create {path}: {e}"))?;
    writeln!(
        f,
        "ts_ns,bid_px,ask_px,bid_qty,ask_qty,trade_px,trade_qty,trade_side"
    )
    .map_err(|e| e.to_string())?;
    for t in ticks {
        writeln!(
            f,
            "{},{:.8},{:.8},{:.8},{:.8},{:.8},{:.8},{}",
            t.ts_ns,
            t.bid_px,
            t.ask_px,
            t.bid_qty,
            t.ask_qty,
            t.trade_px,
            t.trade_qty,
            t.trade_side
        )
        .map_err(|e| e.to_string())?;
    }
    Ok(())
}

fn write_signals_csv(infer: &InferenceResult, path: &str) -> Result<(), String> {
    let mut f = File::create(path).map_err(|e| format!("failed to create {path}: {e}"))?;
    writeln!(f, "ts_ns,prob_down,prob_neutral,prob_up,regime,gate_mean,confidence,label,signal,quote_width_bps,order_size,high_vol_prob").map_err(|e| e.to_string())?;
    for row in &infer.rows {
        writeln!(
            f,
            "{},{:.8},{:.8},{:.8},{},{:.8},{:.8},{},{},{:.8},{:.8},{:.8}",
            row.ts_ns,
            row.prob_down,
            row.prob_neutral,
            row.prob_up,
            row.regime,
            row.gate_mean,
            row.confidence,
            row.label,
            row.signal.as_str(),
            row.quote_width_bps,
            row.order_size,
            row.high_vol_prob
        )
        .map_err(|e| e.to_string())?;
    }
    Ok(())
}

fn read_signal_csv(path: &str) -> Result<Vec<SignalRow>, String> {
    let file = File::open(path).map_err(|e| format!("failed to open {path}: {e}"))?;
    let mut rows = Vec::new();
    for line in BufReader::new(file).lines() {
        let line = line.map_err(|e| e.to_string())?;
        if line.trim().is_empty() || line.starts_with("ts") {
            continue;
        }
        let c = split_csv_simple(&line);
        if c.len() < 12 {
            continue;
        }
        rows.push(SignalRow {
            ts_ns: parse_cell(&c[0], "ts_ns")?,
            prob_down: parse_cell(&c[1], "prob_down")?,
            prob_neutral: parse_cell(&c[2], "prob_neutral")?,
            prob_up: parse_cell(&c[3], "prob_up")?,
            regime: parse_cell(&c[4], "regime")?,
            gate_mean: parse_cell(&c[5], "gate_mean")?,
            confidence: parse_cell(&c[6], "confidence")?,
            label: parse_cell(&c[7], "label")?,
            signal: TradeSignal::from_str(&c[8]),
            quote_width_bps: parse_cell(&c[9], "quote_width_bps")?,
            order_size: parse_cell(&c[10], "order_size")?,
            high_vol_prob: parse_cell(&c[11], "high_vol_prob")?,
        });
    }
    Ok(rows)
}

fn convert_lobster_first_level(
    orderbook_path: &str,
    message_path: &str,
    date_start_ns: i64,
    max_rows: usize,
) -> Result<Vec<LobTick>, String> {
    let ob = File::open(orderbook_path)
        .map_err(|e| format!("failed to open orderbook {orderbook_path}: {e}"))?;
    let msg = File::open(message_path)
        .map_err(|e| format!("failed to open message {message_path}: {e}"))?;
    let mut out = Vec::new();
    for (idx, pair) in BufReader::new(ob)
        .lines()
        .zip(BufReader::new(msg).lines())
        .enumerate()
    {
        if out.len() >= max_rows {
            break;
        }
        let ob_line = pair.0.map_err(|e| e.to_string())?;
        let msg_line = pair.1.map_err(|e| e.to_string())?;
        let obc = split_csv_simple(&ob_line);
        let mc = split_csv_simple(&msg_line);
        if obc.len() < 4 || mc.len() < 6 {
            return Err(format!("bad LOBSTER row {}", idx + 1));
        }
        let seconds: f64 = parse_cell(&mc[0], "seconds")?;
        let ask_px = normalize_lobster_price(parse_cell::<f64>(&obc[0], "ask_px")?);
        let ask_qty = parse_cell(&obc[1], "ask_qty")?;
        let bid_px = normalize_lobster_price(parse_cell::<f64>(&obc[2], "bid_px")?);
        let bid_qty = parse_cell(&obc[3], "bid_qty")?;
        let trade_px = normalize_lobster_price(parse_cell::<f64>(&mc[4], "trade_px")?);
        let trade_qty = parse_cell(&mc[3], "trade_qty")?;
        let direction: i8 = parse_cell(&mc[5], "direction")?;
        out.push(LobTick {
            ts_ns: date_start_ns + (seconds * 1_000_000_000.0) as i64,
            bid_px,
            ask_px,
            bid_qty,
            ask_qty,
            trade_px: if trade_px > 0.0 {
                trade_px
            } else {
                0.5 * (bid_px + ask_px)
            },
            trade_qty,
            trade_side: direction.signum(),
        });
    }
    Ok(out)
}

fn normalize_lobster_price(px: f64) -> f64 {
    if px.abs() > 10_000.0 {
        px / 10_000.0
    } else {
        px
    }
}

fn write_audit_json(audit: &SignalAudit, path: &str) -> Result<(), String> {
    let mut signals = String::new();
    for (idx, (name, count)) in audit.signal_counts.iter().enumerate() {
        if idx > 0 {
            signals.push_str(", ");
        }
        signals.push_str(&format!("\"{}\": {}", json_escape(name), count));
    }
    let json = format!(
        "{{\n  \"schema\": \"lobframe.hftbt.signal_audit.v1\",\n  \"status\": \"{}\",\n  \"rows\": {},\n  \"timestamp_monotonic\": {},\n  \"probability_sum_ok\": {},\n  \"finite\": {},\n  \"avg_gate\": {:.8},\n  \"avg_confidence\": {:.8},\n  \"min_confidence\": {:.8},\n  \"max_confidence\": {:.8},\n  \"signal_counts\": {{{}}}\n}}\n",
        audit.status,
        audit.rows,
        audit.timestamp_monotonic,
        audit.probability_sum_ok,
        audit.finite,
        audit.avg_gate,
        audit.avg_confidence,
        audit.min_confidence,
        audit.max_confidence,
        signals
    );
    fs::write(path, json).map_err(|e| format!("failed to write {path}: {e}"))
}

fn write_backtest_report_json(report: &BacktestReport, path: &str) -> Result<(), String> {
    let mut cfg = String::new();
    for (idx, (k, v)) in report.config.iter().enumerate() {
        if idx > 0 {
            cfg.push_str(", ");
        }
        cfg.push_str(&format!("\"{}\": \"{}\"", json_escape(k), json_escape(v)));
    }
    let mut regimes = String::new();
    for (idx, (k, v)) in report.model_summary.regime_counts.iter().enumerate() {
        if idx > 0 {
            regimes.push_str(", ");
        }
        regimes.push_str(&format!("\"{}\": {}", k, v));
    }
    let checks = report
        .invariants
        .checks
        .iter()
        .map(|c| {
            format!(
                "{{\"name\":\"{}\",\"passed\":{},\"severity\":\"{}\",\"detail\":\"{}\"}}",
                json_escape(&c.name),
                c.passed,
                json_escape(&c.severity),
                json_escape(&c.detail)
            )
        })
        .collect::<Vec<_>>()
        .join(",\n      ");

    let json = format!(
        "{{\n  \"schema\": \"{}\",\n  \"version\": \"{}\",\n  \"status\": \"{}\",\n  \"metrics\": {{\n    \"rows\": {},\n    \"trades\": {},\n    \"fills\": {},\n    \"fill_ratio\": {:.8},\n    \"total_pnl\": {:.8},\n    \"total_fees\": {:.8},\n    \"equity_final\": {:.8},\n    \"sharpe\": {:.8},\n    \"sortino\": {:.8},\n    \"max_drawdown\": {:.8},\n    \"win_rate\": {:.8},\n    \"final_inventory\": {:.8}\n  }},\n  \"feature_summary\": {{\n    \"rows\": {},\n    \"avg_spread_bps\": {:.8},\n    \"avg_abs_imbalance\": {:.8},\n    \"avg_abs_ofi\": {:.8},\n    \"avg_sigma\": {:.8},\n    \"avg_lambda\": {:.8}\n  }},\n  \"model_summary\": {{\n    \"avg_gate\": {:.8},\n    \"avg_confidence\": {:.8},\n    \"posterior_entropy\": {:.8},\n    \"regime_counts\": {{{}}}\n  }},\n  \"confusion\": [[{}, {}, {}], [{}, {}, {}], [{}, {}, {}]],\n  \"invariants\": {{\n    \"status\": \"{}\",\n    \"checks\": [\n      {}\n    ]\n  }},\n  \"config\": {{{}}}\n}}\n",
        json_escape(&report.schema),
        json_escape(&report.version),
        json_escape(&report.invariants.status),
        report.metrics.rows,
        report.metrics.trades,
        report.metrics.fills,
        report.metrics.fill_ratio,
        report.metrics.total_pnl,
        report.metrics.total_fees,
        report.metrics.equity_final,
        report.metrics.sharpe,
        report.metrics.sortino,
        report.metrics.max_drawdown,
        report.metrics.win_rate,
        report.metrics.final_inventory,
        report.feature_summary.rows,
        report.feature_summary.avg_spread_bps,
        report.feature_summary.avg_abs_imbalance,
        report.feature_summary.avg_abs_ofi,
        report.feature_summary.avg_sigma,
        report.feature_summary.avg_lambda,
        report.model_summary.avg_gate,
        report.model_summary.avg_confidence,
        report.model_summary.posterior_entropy,
        regimes,
        report.confusion[0][0], report.confusion[0][1], report.confusion[0][2],
        report.confusion[1][0], report.confusion[1][1], report.confusion[1][2],
        report.confusion[2][0], report.confusion[2][1], report.confusion[2][2],
        json_escape(&report.invariants.status),
        checks,
        cfg
    );
    fs::write(path, json).map_err(|e| format!("failed to write {path}: {e}"))
}

fn print_backtest_console(report: &BacktestReport, elapsed: f64, path: &str) {
    println!("=== LOBFRAME HFTBT PRODUCTION REPORT ===");
    println!(
        "status={} version={} elapsed_ms={:.3}",
        report.invariants.status,
        report.version,
        elapsed * 1000.0
    );
    println!(
        "pnl={:.6} trades={} fills={} fill_ratio={:.2}% fees={:.6} sharpe={:.4} max_dd={:.4}",
        report.metrics.total_pnl,
        report.metrics.trades,
        report.metrics.fills,
        report.metrics.fill_ratio * 100.0,
        report.metrics.total_fees,
        report.metrics.sharpe,
        report.metrics.max_drawdown
    );
    println!(
        "features rows={} spread_bps={:.4} abs_imb={:.4} abs_ofi={:.4} sigma={:.4} lambda={:.4}",
        report.feature_summary.rows,
        report.feature_summary.avg_spread_bps,
        report.feature_summary.avg_abs_imbalance,
        report.feature_summary.avg_abs_ofi,
        report.feature_summary.avg_sigma,
        report.feature_summary.avg_lambda
    );
    println!(
        "model gate={:.4} confidence={:.4} posterior_entropy={:.4}",
        report.model_summary.avg_gate,
        report.model_summary.avg_confidence,
        report.model_summary.posterior_entropy
    );
    for check in &report.invariants.checks {
        println!(
            "gate {} {}: {}",
            if check.passed {
                "PASS"
            } else {
                &check.severity
            },
            check.name,
            check.detail
        );
    }
    println!("report={path}");
    println!("=== END LOBFRAME HFTBT PRODUCTION REPORT ===");
}

