mod hyperliquid {
    // ===== source: collector/src/hyperliquid/mod.rs =====
    mod http {
        // ===== source: collector/src/hyperliquid/http.rs =====
        use std::{
            io,
            io::ErrorKind,
            time::{Duration, Instant},
        };

        use anyhow::Error;
        use chrono::{DateTime, Utc};
        use futures_util::{SinkExt, StreamExt};
        use tokio::{
            select,
            sync::mpsc::{UnboundedSender, unbounded_channel},
        };
        use tokio_tungstenite::{
            connect_async,
            tungstenite::{Message, Utf8Bytes, client::IntoClientRequest},
        };
        use tracing::{error, info, warn};

        pub async fn connect(
            url: &str,
            subscriptions: Vec<serde_json::Value>,
            ws_tx: UnboundedSender<(DateTime<Utc>, Utf8Bytes)>,
        ) -> Result<(), anyhow::Error> {
            let request = url.into_client_request()?;
            let (ws_stream, _) = connect_async(request).await?;
            let (mut write, mut read) = ws_stream.split();
            let (_ping_tx, mut ping_rx) = unbounded_channel::<()>();

            for subscription in subscriptions {
                write
                    .send(Message::Text(subscription.to_string().into()))
                    .await?;
            }

            tokio::spawn(async move {
                let mut ping_interval = tokio::time::interval(Duration::from_secs(30));
                loop {
                    select! {
                        _ = ping_interval.tick() => {
                            if write.send(Message::Text(r#"{"method":"ping"}"#.into())).await.is_err() {
                                return;
                            }
                        }
                        result = ping_rx.recv() => {
                            if result.is_none() {
                                break;
                            }
                        }
                    }
                }
            });

            loop {
                match read.next().await {
                    Some(Ok(Message::Text(text))) => {
                        let recv_time = Utc::now();

                        if let Ok(j) = serde_json::from_str::<serde_json::Value>(&text)
                            && j.get("channel").and_then(|c| c.as_str()) == Some("pong")
                        {
                            continue;
                        }

                        if ws_tx.send((recv_time, text)).is_err() {
                            break;
                        }
                    }
                    Some(Ok(Message::Binary(_))) => {}
                    Some(Ok(Message::Ping(_))) => {
                        // Hyperliquid uses JSON ping/pong, not WebSocket ping/pong
                    }
                    Some(Ok(Message::Pong(_))) => {}
                    Some(Ok(Message::Close(close_frame))) => {
                        warn!(?close_frame, "connection closed");
                        return Err(Error::from(io::Error::new(
                            ErrorKind::ConnectionAborted,
                            "connection closed",
                        )));
                    }
                    Some(Ok(Message::Frame(_))) => {}
                    Some(Err(e)) => {
                        return Err(Error::from(e));
                    }
                    None => {
                        break;
                    }
                }
            }
            Ok(())
        }

        pub async fn keep_connection(
            subscription_types: Vec<String>,
            symbol_list: Vec<String>,
            ws_tx: UnboundedSender<(DateTime<Utc>, Utf8Bytes)>,
        ) {
            let mut error_count = 0;
            loop {
                let connect_time = Instant::now();

                let subscriptions: Vec<serde_json::Value> = symbol_list
                    .iter()
                    .flat_map(|symbol| {
                        subscription_types.iter().map(move |sub_type| {
                            serde_json::json!({
                                "method": "subscribe",
                                "subscription": {
                                    "type": sub_type,
                                    "coin": symbol
                                }
                            })
                        })
                    })
                    .collect();

                info!(
                    "Connecting to Hyperliquid WebSocket with {} subscriptions",
                    subscriptions.len()
                );

                if let Err(error) =
                    connect("wss://api.hyperliquid.xyz/ws", subscriptions, ws_tx.clone()).await
                {
                    error!(?error, "websocket error");
                    error_count += 1;
                    if connect_time.elapsed() > Duration::from_secs(30) {
                        error_count = 0;
                    }

                    let sleep_duration = if error_count > 20 {
                        Duration::from_secs(10)
                    } else if error_count > 10 {
                        Duration::from_secs(5)
                    } else if error_count > 3 {
                        Duration::from_secs(1)
                    } else {
                        Duration::from_millis(500)
                    };

                    tokio::time::sleep(sleep_duration).await;
                } else {
                    break;
                }
            }
        }
    }

    use chrono::{DateTime, Utc};
    pub use http::keep_connection;
    use tokio::sync::mpsc::UnboundedSender;
    use tokio_tungstenite::tungstenite::Utf8Bytes;
    use tracing::error;

    use crate::error::ConnectorError;

    fn handle(
        writer_tx: &UnboundedSender<(DateTime<Utc>, String, String)>,
        recv_time: DateTime<Utc>,
        data: Utf8Bytes,
    ) -> Result<(), ConnectorError> {
        let j: serde_json::Value = serde_json::from_str(data.as_str())?;

        if let Some(channel) = j.get("channel") {
            let channel_str = channel.as_str().ok_or(ConnectorError::FormatError)?;

            if channel_str == "subscriptionResponse" {
                return Ok(());
            }

            if let Some(data_obj) = j.get("data") {
                let symbol = match channel_str {
                    "trades" => {
                        if let Some(trades) = data_obj.as_array() {
                            if let Some(first_trade) = trades.first() {
                                first_trade
                                    .get("coin")
                                    .and_then(|c| c.as_str())
                                    .ok_or(ConnectorError::FormatError)?
                            } else {
                                return Ok(());
                            }
                        } else {
                            return Err(ConnectorError::FormatError);
                        }
                    }
                    "l2Book" => data_obj
                        .get("coin")
                        .and_then(|c| c.as_str())
                        .ok_or(ConnectorError::FormatError)?,
                    "bbo" => data_obj
                        .get("coin")
                        .and_then(|c| c.as_str())
                        .ok_or(ConnectorError::FormatError)?,
                    _ => {
                        if let Some(coin) = data_obj.get("coin").and_then(|c| c.as_str()) {
                            coin
                        } else {
                            return Ok(());
                        }
                    }
                };

                let _ = writer_tx.send((recv_time, symbol.to_string(), data.to_string()));
            }
        }

        Ok(())
    }

    pub async fn run_collection(
        subscriptions: Vec<String>,
        symbols: Vec<String>,
        writer_tx: UnboundedSender<(DateTime<Utc>, String, String)>,
    ) -> Result<(), anyhow::Error> {
        let (ws_tx, mut ws_rx) = tokio::sync::mpsc::unbounded_channel();
        let h = tokio::spawn(keep_connection(subscriptions, symbols, ws_tx.clone()));

        while let Some((recv_time, data)) = ws_rx.recv().await {
            if let Err(error) = handle(&writer_tx, recv_time, data) {
                error!(?error, "couldn't handle the received data.");
            }
        }
        let _ = h.await;
        Ok(())
    }
}
#[cfg(feature = "single_file_collector")]
mod throttler {
    // ===== source: collector/src/throttler.rs =====
    use std::{future::Future, sync::Arc};

    use chrono::Utc;
    use tokio::sync::Mutex;

    #[derive(Clone)]
    pub struct Throttler {
        exec_ts: Arc<Mutex<Vec<i64>>>,
        rate_limit: usize,
    }

    impl Throttler {
        pub fn new(rate_limit: usize) -> Self {
            Self {
                exec_ts: Default::default(),
                rate_limit,
            }
        }

        pub async fn execute<Fut, T>(&mut self, fut: Fut) -> Option<T>
        where
            Fut: Future<Output = T>,
        {
            let cur_ts = Utc::now().timestamp_nanos_opt().unwrap();
            {
                let mut exec_ts_ = self.exec_ts.lock().await;
                exec_ts_.retain(|ts| *ts > cur_ts - 60_000_000_000);
                if exec_ts_.len() > self.rate_limit {
                    return None;
                }
                exec_ts_.push(cur_ts);
            }
            Some(fut.await)
        }
    }
}

#[cfg(feature = "single_file_collector")]
#[derive(Parser, Debug)]
#[command(version, about, long_about = None)]
struct Args {
    /// Path for the files where collected data will be written.
    path: String,

    /// Name of the exchange
    exchange: String,

    /// Symbols for which data will be collected.
    symbols: Vec<String>,
}

#[cfg(feature = "single_file_collector")]
#[tokio::main(flavor = "multi_thread")]
async fn main() -> Result<(), anyhow::Error> {
    let args = Args::parse();

    tracing_subscriber::fmt::init();

    let (writer_tx, mut writer_rx) = unbounded_channel();

    let handle = match args.exchange.as_str() {
        "binancefutures" | "binancefuturesum" => {
            let streams = [
                "$symbol@trade",
                "$symbol@bookTicker",
                "$symbol@depth@0ms",
                // "$symbol@@markPrice@1s"
            ]
            .iter()
            .map(|stream| stream.to_string())
            .collect();

            tokio::spawn(binancefuturesum::run_collection(
                streams,
                args.symbols,
                writer_tx,
            ))
        }
        "binancefuturescm" => {
            let streams = [
                "$symbol@trade",
                "$symbol@bookTicker",
                "$symbol@depth@0ms",
                // "$symbol@@markPrice@1s"
            ]
            .iter()
            .map(|stream| stream.to_string())
            .collect();

            tokio::spawn(binancefuturescm::run_collection(
                streams,
                args.symbols,
                writer_tx,
            ))
        }
        "binance" | "binancespot" => {
            let streams = ["$symbol@trade", "$symbol@bookTicker", "$symbol@depth@100ms"]
                .iter()
                .map(|stream| stream.to_string())
                .collect();

            tokio::spawn(binance::run_collection(streams, args.symbols, writer_tx))
        }
        "bybit" => {
            let topics = [
                "orderbook.1.$symbol",
                "orderbook.50.$symbol",
                "orderbook.500.$symbol",
                "publicTrade.$symbol",
            ]
            .iter()
            .map(|topic| topic.to_string())
            .collect();

            tokio::spawn(bybit::run_collection(topics, args.symbols, writer_tx))
        }
        "hyperliquid" => {
            let subscriptions = ["trades", "l2Book", "bbo"]
                .iter()
                .map(|sub| sub.to_string())
                .collect();

            tokio::spawn(hyperliquid::run_collection(
                subscriptions,
                args.symbols,
                writer_tx,
            ))
        }
        exchange => {
            return Err(anyhow!("{exchange} is not supported."));
        }
    };

    let mut writer = Writer::new(&args.path);
    loop {
        select! {
            _ = signal::ctrl_c() => {
                info!("ctrl-c received");
                break;
            }
            r = writer_rx.recv() => match r {
                Some((recv_time, symbol, data)) => {
                    if let Err(error) = writer.write(recv_time, symbol, data) {
                        error!(?error, "write error");
                        break;
                    }
                }
                None => {
                    break;
                }
            }
        }
    }
    // let _ = handle.await;
    Ok(())
}

