mod utils {
    // ===== source: connector/src/utils.rs =====
    use std::{
        fmt,
        fmt::{Debug, Write},
        future::Future,
        marker::PhantomData,
        time::{Duration, Instant},
    };

    use base64::{Engine as _, engine::general_purpose};
    use chrono::Utc;
    use ed25519_dalek::{
        Signature as Ed25519Signature, Signer, SigningKey, pkcs8::DecodePrivateKey,
    };
    use hashbrown::Equivalent;
    use hftbacktest::prelude::OrderId;
    use hmac::{Hmac, Mac};
    use rand::Rng;
    use serde::{
        Deserialize, Deserializer, de,
        de::{Error, Visitor},
    };
    use sha2::Sha256;

    use crate::bybit::BybitError;

    struct I64Visitor;

    impl Visitor<'_> for I64Visitor {
        type Value = Option<i64>;

        fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
            formatter.write_str("a string containing an i64 number")
        }

        fn visit_str<E>(self, s: &str) -> Result<Self::Value, E>
        where
            E: de::Error,
        {
            if s.is_empty() {
                Ok(Some(0))
            } else {
                Ok(Some(s.parse::<i64>().map_err(Error::custom)?))
            }
        }
    }

    struct OptionF64Visitor;

    impl<'de> Visitor<'de> for OptionF64Visitor {
        type Value = Option<f64>;

        fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
            formatter.write_str("a string containing an f64 number")
        }

        fn visit_none<E>(self) -> Result<Self::Value, E>
        where
            E: Error,
        {
            Ok(None)
        }

        fn visit_some<D>(self, deserializer: D) -> Result<Self::Value, D::Error>
        where
            D: Deserializer<'de>,
        {
            deserializer.deserialize_str(F64Visitor)
        }
    }

    struct F64Visitor;

    impl Visitor<'_> for F64Visitor {
        type Value = Option<f64>;

        fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
            formatter.write_str("a string containing an f64 number")
        }

        fn visit_str<E>(self, s: &str) -> Result<Self::Value, E>
        where
            E: de::Error,
        {
            if s.is_empty() {
                Ok(None)
            } else {
                Ok(Some(s.parse::<f64>().map_err(Error::custom)?))
            }
        }
    }

    pub fn from_str_to_i64<'de, D>(deserializer: D) -> Result<i64, D::Error>
    where
        D: Deserializer<'de>,
    {
        deserializer
            .deserialize_str(I64Visitor)
            .map(|value| value.unwrap_or(0))
    }

    pub fn from_str_to_f64<'de, D>(deserializer: D) -> Result<f64, D::Error>
    where
        D: Deserializer<'de>,
    {
        deserializer
            .deserialize_str(F64Visitor)
            .map(|value| value.unwrap_or(0.0))
    }

    pub fn from_str_to_f64_opt<'de, D>(deserializer: D) -> Result<Option<f64>, D::Error>
    where
        D: Deserializer<'de>,
    {
        deserializer.deserialize_option(OptionF64Visitor)
    }

    pub fn to_uppercase<'de, D>(deserializer: D) -> Result<String, D::Error>
    where
        D: Deserializer<'de>,
    {
        let s: &str = Deserialize::deserialize(deserializer)?;
        Ok(s.to_uppercase())
    }

    pub fn to_lowercase<'de, D>(deserializer: D) -> Result<String, D::Error>
    where
        D: Deserializer<'de>,
    {
        let s: &str = Deserialize::deserialize(deserializer)?;
        Ok(s.to_lowercase())
    }

    pub fn sign_hmac_sha256(secret: &str, s: &str) -> String {
        let mut mac = Hmac::<Sha256>::new_from_slice(secret.as_bytes()).unwrap();
        mac.update(s.as_bytes());
        let hash = mac.finalize().into_bytes();
        let mut tmp = String::with_capacity(hash.len() * 2);
        for c in hash {
            write!(&mut tmp, "{c:02x}").unwrap();
        }
        tmp
    }

    pub fn sign_ed25519(private_key: &str, s: &str) -> String {
        let private_key = SigningKey::from_pkcs8_pem(private_key).unwrap();
        let signature: Ed25519Signature = private_key.sign(s.as_bytes());
        general_purpose::STANDARD.encode(signature.to_bytes())
    }

    pub fn get_timestamp() -> u64 {
        Utc::now().timestamp_millis() as u64
    }

    pub type PxQty = (f64, f64);

    pub fn parse_depth(
        bids: Vec<(String, String)>,
        asks: Vec<(String, String)>,
    ) -> Result<(Vec<PxQty>, Vec<PxQty>), BybitError> {
        let mut bids_ = Vec::with_capacity(bids.len());
        for (px, qty) in bids {
            bids_.push(parse_px_qty_tup(px, qty)?);
        }
        let mut asks_ = Vec::with_capacity(asks.len());
        for (px, qty) in asks {
            asks_.push(parse_px_qty_tup(px, qty)?);
        }
        Ok((bids_, asks_))
    }

    pub fn parse_px_qty_tup(px: String, qty: String) -> Result<PxQty, BybitError> {
        Ok((px.parse()?, qty.parse()?))
    }

    pub trait BackoffStrategy {
        fn backoff(&mut self) -> Duration;
    }

    pub struct ExponentialBackoff {
        last_attempt: Instant,
        factor: u32,
        last_delay: Option<Duration>,
        reset_interval: Option<Duration>,
        min_delay: Duration,
        max_delay: Option<Duration>,
    }

    impl Default for ExponentialBackoff {
        fn default() -> Self {
            Self {
                last_attempt: Instant::now(),
                factor: 2,
                last_delay: None,
                reset_interval: Some(Duration::from_secs(300)),
                min_delay: Duration::from_millis(100),
                max_delay: Some(Duration::from_secs(60)),
            }
        }
    }

    impl BackoffStrategy for ExponentialBackoff {
        fn backoff(&mut self) -> Duration {
            if let Some(reset_interval) = self.reset_interval
                && self.last_attempt.elapsed() > reset_interval
            {
                self.last_delay = None;
            }

            self.last_attempt = Instant::now();

            match self.last_delay {
                None => {
                    self.last_delay = Some(self.min_delay);
                    self.min_delay
                }
                Some(last_delay) => {
                    let mut delay = last_delay.saturating_mul(self.factor);

                    if let Some(max_delay) = self.max_delay
                        && delay > max_delay
                    {
                        delay = max_delay;
                    }
                    self.last_delay = Some(delay);
                    delay
                }
            }
        }
    }

    pub struct Retry<O, E, Backoff, ErrorHandler> {
        backoff: Backoff,
        error_handler: Option<ErrorHandler>,
        _o_marker: PhantomData<O>,
        _e_marker: PhantomData<E>,
    }

    impl<O, E, Backoff, ErrorHandler> Retry<O, E, Backoff, ErrorHandler>
    where
        E: Debug,
        Backoff: BackoffStrategy,
        ErrorHandler: FnMut(E) -> Result<(), E>,
    {
        pub fn new(backoff: Backoff) -> Self {
            Self {
                backoff,
                error_handler: None,
                _o_marker: Default::default(),
                _e_marker: Default::default(),
            }
        }

        pub fn error_handler(self, error_handler: ErrorHandler) -> Self {
            Self {
                error_handler: Some(error_handler),
                ..self
            }
        }

        pub async fn retry<F, Fut>(&mut self, func: F) -> Result<O, E>
        where
            F: Fn() -> Fut,
            Fut: Future<Output = Result<O, E>>,
        {
            loop {
                match func().await {
                    Ok(o) => return Ok(o),
                    Err(error) => {
                        if let Some(error_handler) = self.error_handler.as_mut() {
                            error_handler(error)?;
                        }
                        tokio::time::sleep(self.backoff.backoff()).await;
                    }
                }
            }
        }
    }

    #[derive(Eq, Hash, PartialEq, Debug)]
    pub struct SymbolOrderId {
        pub symbol: String,
        pub order_id: OrderId,
    }

    impl SymbolOrderId {
        pub fn new(symbol: String, order_id: OrderId) -> Self {
            Self { symbol, order_id }
        }
    }

    #[derive(Eq, Hash, PartialEq, Debug)]
    pub struct RefSymbolOrderId<'a> {
        pub symbol: &'a str,
        pub order_id: OrderId,
    }

    impl<'a> RefSymbolOrderId<'a> {
        pub fn new(symbol: &'a str, order_id: OrderId) -> Self {
            Self { symbol, order_id }
        }
    }

    impl Equivalent<SymbolOrderId> for RefSymbolOrderId<'_> {
        fn equivalent(&self, key: &SymbolOrderId) -> bool {
            key.symbol == self.symbol && key.order_id == self.order_id
        }
    }

    pub fn generate_rand_string(length: usize) -> String {
        const CHARSET: &[u8] = b"ABCDEFGHIJKLMNOPQRSTUVWXYZ\
                             abcdefghijklmnopqrstuvwxyz\
                             0123456789";
        let mut rng = rand::rng();
        (0..length)
            .map(|_| {
                let idx = rng.random_range(0..CHARSET.len());
                CHARSET[idx] as char
            })
            .collect()
    }

    #[cfg(test)]
    mod tests {
        use std::{
            thread,
            time::{Duration, Instant},
        };

        use hashbrown::HashMap;

        use crate::utils::{BackoffStrategy, ExponentialBackoff, RefSymbolOrderId, SymbolOrderId};

        #[test]
        fn equivalent_symbol_order_id() {
            let mut map = HashMap::new();
            map.insert(
                SymbolOrderId::new("key1".to_string(), 1),
                "value1".to_string(),
            );

            assert_eq!(
                map.get(&RefSymbolOrderId::new("key1", 1)).unwrap(),
                "value1"
            )
        }

        #[test]
        fn test_backoff() {
            let mut backoff = ExponentialBackoff {
                last_attempt: Instant::now(),
                factor: 2,
                last_delay: None,
                reset_interval: None,
                min_delay: Duration::from_millis(0),
                max_delay: None,
            };

            let mut value = Duration::from_secs(0);
            for _ in 0..10 {
                let new_value = backoff.backoff();
                assert_eq!(new_value, value * backoff.factor);
                value = new_value;
            }
        }

        #[test]
        fn test_backoff_min_delay() {
            let mut backoff = ExponentialBackoff {
                last_attempt: Instant::now(),
                factor: 2,
                last_delay: None,
                reset_interval: None,
                min_delay: Duration::from_millis(100),
                max_delay: None,
            };

            assert_eq!(backoff.backoff(), backoff.min_delay);
        }

        #[test]
        fn test_backoff_max_delay() {
            let mut backoff = ExponentialBackoff {
                last_attempt: Instant::now(),
                factor: 2,
                last_delay: None,
                reset_interval: None,
                min_delay: Duration::from_millis(100),
                max_delay: Some(Duration::from_secs(1)),
            };

            for _ in 0..100 {
                backoff.backoff();
            }
            assert_eq!(backoff.backoff(), backoff.max_delay.unwrap());
        }

        #[test]
        fn test_backoff_reset_interval() {
            let mut backoff = ExponentialBackoff {
                last_attempt: Instant::now(),
                factor: 2,
                last_delay: None,
                reset_interval: Some(Duration::from_secs(5)),
                min_delay: Duration::from_millis(100),
                max_delay: Some(Duration::from_secs(1)),
            };

            for _ in 0..100 {
                let new_value = backoff.backoff();
                if new_value == backoff.max_delay.unwrap() {
                    thread::sleep(backoff.reset_interval.unwrap() + Duration::from_millis(100));
                    assert_eq!(backoff.backoff(), backoff.min_delay);
                    return;
                } else {
                    thread::sleep(Duration::from_millis(100));
                }
            }
            panic!();
        }
    }
}

#[cfg(feature = "single_file_connector")]
struct Position {
    qty: f64,
    exch_ts: i64,
}

#[cfg(feature = "single_file_connector")]
fn run_receive_task(
    name: &str,
    tx: UnboundedSender<PublishEvent>,
    connector: &mut Box<dyn Connector>,
) -> Result<(), ChannelError> {
    let node = NodeBuilder::new()
        .signal_handling_mode(SignalHandlingMode::Disabled)
        .create::<ipc::Service>()
        .map_err(|error| ChannelError::BuildError(error.to_string()))?;
    let bot_rx = IceoryxBuilder::new(name).bot(false).receiver()?;
    loop {
        let cycle_time = Duration::from_nanos(1000);
        match node.wait(cycle_time) {
            Ok(()) => {
                while let Some((id, ev)) = bot_rx.receive()? {
                    match ev {
                        LiveRequest::Order {
                            symbol: asset,
                            order,
                        } => match order.req {
                            Status::New => {
                                // Requests to the Connector submit the new order.
                                connector.submit(asset, order, tx.clone());
                            }
                            Status::Canceled => {
                                // Requests to the Connector cancel the order.
                                connector.cancel(asset, order, tx.clone());
                            }
                            status => {
                                error!(?status, "An invalid request was received from the bot.");
                            }
                        },
                        LiveRequest::RegisterInstrument {
                            symbol,
                            tick_size,
                            lot_size,
                        } => {
                            // Makes prepare the publisher thread to also add the instrument.
                            tx.send(PublishEvent::RegisterInstrument {
                                id,
                                symbol: symbol.clone(),
                                tick_size,
                                lot_size,
                            })
                            .unwrap();
                            // Requests to the Connector subscribe to the necessary feeds for the
                            // instrument.
                            connector.register(symbol);
                        }
                    }
                }
            }
            Err(_error) => {
                break;
            }
        }
    }
    Ok(())
}

#[cfg(feature = "single_file_connector")]
async fn run_publish_task(
    name: &str,
    order_manager: Arc<Mutex<dyn GetOrders>>,
    mut rx: UnboundedReceiver<PublishEvent>,
    shutdown_signal: Arc<Notify>,
) -> Result<(), ChannelError> {
    let mut depth = HashMap::new();
    let mut position: HashMap<String, Position> = HashMap::new();
    let bot_tx = IceoryxBuilder::new(name).bot(false).sender()?;

    loop {
        select! {
            _ = shutdown_signal.notified() => {
                break;
            }
            Some(msg) = rx.recv() => {
                match msg {
                    PublishEvent::RegisterInstrument {
                        id,
                        symbol,
                        tick_size,
                        lot_size,
                    } => {
                        // Sends the current state (orders, position, and market depth) to the bot that
                        // requested to add this instrument in batch mode.
                        bot_tx.send(id, &LiveEvent::BatchStart)?;

                        for order in order_manager.lock().unwrap().orders(Some(symbol.clone())) {
                            bot_tx.send(
                                id,
                                &LiveEvent::Order {
                                    symbol: symbol.clone(),
                                    order,
                                },
                            )?;
                        }

                        if let Some(position) = position.get(&symbol) {
                            bot_tx.send(
                                id,
                                &LiveEvent::Position {
                                    symbol: symbol.clone(),
                                    qty: position.qty,
                                    exch_ts: position.exch_ts,
                                },
                            )?;
                        }

                        match depth.entry(symbol) {
                            Entry::Occupied(mut entry) => {
                                let depth_: &mut FusedHashMapMarketDepth = entry.get_mut();
                                let snapshot = depth_.snapshot();
                                for event in snapshot {
                                    bot_tx.send(
                                        id,
                                        &LiveEvent::Feed {
                                            symbol: entry.key().clone(),
                                            event,
                                        },
                                    )?;
                                }
                            }
                            Entry::Vacant(entry) => {
                                entry.insert(FusedHashMapMarketDepth::new(tick_size, lot_size));
                            }
                        }

                        bot_tx.send(id, &LiveEvent::BatchEnd)?;
                    }
                    PublishEvent::LiveEvent(ev) => {
                        // The live event will only be published if the result is true.
                        for ev in handle_ev(ev, &mut depth, &mut position) {
                            bot_tx.send(TO_ALL, &ev)?;
                        }
                    }
                    PublishEvent::BatchStart(id) => {
                        bot_tx.send(id, &LiveEvent::BatchStart)?;
                    }
                    PublishEvent::BatchEnd(id) => {
                        bot_tx.send(id, &LiveEvent::BatchEnd)?;
                    }
                }
            }
        }
    }
    Ok(())
}

/// Maintains the market depth for all added instruments, allowing another bot to request the same
/// instrument and publishing the market depth snapshot, and fuses the market depth from different
/// streams, such as L1 or L2 with varying depths and update frequencies, to provide the most
/// granular and frequent updates.
///
/// Returns true when the received live event needs to be published; otherwise, it does not.
/// For example, publication is unnecessary if the received market depth data is outdated by more
/// recent data from a different stream due to fusion.
#[cfg(feature = "single_file_connector")]
fn handle_ev(
    ev: LiveEvent,
    depth: &mut HashMap<String, FusedHashMapMarketDepth>,
    position: &mut HashMap<String, Position>,
) -> Vec<LiveEvent> {
    match &ev {
        LiveEvent::Feed { symbol, event } => {
            if event.is(BUY_EVENT | DEPTH_EVENT) {
                let depth_ = {
                    match depth.get_mut(symbol) {
                        Some(d) => d,
                        None => return vec![],
                    }
                };
                return depth_
                    .update_bid_depth(event.clone())
                    .iter()
                    .map(|event| LiveEvent::Feed {
                        symbol: symbol.clone(),
                        event: event.clone(),
                    })
                    .collect();
            } else if event.is(SELL_EVENT | DEPTH_EVENT) {
                let depth_ = {
                    match depth.get_mut(symbol) {
                        Some(d) => d,
                        None => return vec![],
                    }
                };
                return depth_
                    .update_ask_depth(event.clone())
                    .iter()
                    .map(|event| LiveEvent::Feed {
                        symbol: symbol.clone(),
                        event: event.clone(),
                    })
                    .collect();
            } else if event.is(BUY_EVENT | DEPTH_BBO_EVENT) {
                let depth_ = {
                    match depth.get_mut(symbol) {
                        Some(d) => d,
                        None => return vec![],
                    }
                };
                return depth_
                    .update_best_bid(event.clone())
                    .iter()
                    .map(|event| LiveEvent::Feed {
                        symbol: symbol.clone(),
                        event: event.clone(),
                    })
                    .collect();
            } else if event.is(SELL_EVENT | DEPTH_BBO_EVENT) {
                let depth_ = {
                    match depth.get_mut(symbol) {
                        Some(d) => d,
                        None => return vec![],
                    }
                };
                return depth_
                    .update_best_ask(event.clone())
                    .iter()
                    .map(|event| LiveEvent::Feed {
                        symbol: symbol.clone(),
                        event: event.clone(),
                    })
                    .collect();
            } else if event.is(DEPTH_CLEAR_EVENT) {
                let depth_ = {
                    match depth.get_mut(symbol) {
                        Some(d) => d,
                        None => return vec![],
                    }
                };
                depth_.clear_depth(Side::None, 0.0, 0);
            }
        }
        LiveEvent::Position {
            symbol,
            qty,
            exch_ts,
        } => {
            if position.contains_key(symbol) {
                let position = position.get_mut(symbol).unwrap();
                return if *exch_ts >= position.exch_ts {
                    position.qty = *qty;
                    vec![ev]
                } else {
                    vec![]
                };
            } else {
                position.insert(
                    symbol.clone(),
                    Position {
                        qty: *qty,
                        exch_ts: *exch_ts,
                    },
                );
                return vec![ev];
            }
        }
        _ => {}
    }
    vec![ev]
}

#[cfg(feature = "single_file_connector")]
#[derive(Parser, Debug)]
#[command(version, about, long_about = None)]
struct Args {
    /// Name of the connector, used when connecting the bot to the connector.
    name: String,

    /// Connector
    /// * binancefutures: Binance USD-m Futures
    /// * bybit: Bybit Linear Futures
    connector: String,

    /// Connector's configuration file path.
    config: String,
}

#[cfg(feature = "single_file_connector")]
#[tokio::main]
async fn main() {
    // Ensures that the main thread will terminate if any of its child threads panics.
    let orig_hook = panic::take_hook();
    panic::set_hook(Box::new(move |panic_info| {
        orig_hook(panic_info);
        exit(1);
    }));

    let args = Args::parse();

    tracing_subscriber::fmt::init();

    // Listen for shut down signal and notify publish task.
    let shutdown_signal = Arc::new(Notify::new());
    let shutdown_signal_ = shutdown_signal.clone();
    tokio::spawn(async move {
        #[cfg(unix)]
        {
            // Wait for either SIGINT (CTRL+C) or SIGTERM on Unix.
            let mut sigterm = signal::unix::signal(signal::unix::SignalKind::terminate())
                .expect("failed to install SIGTERM handler");
            select! {
                _ = signal::ctrl_c() => {},
                _ = sigterm.recv() => {},
            }
        }
        #[cfg(not(unix))]
        {
            // Non-Unix platforms only has SIGINT.
            if let Err(error) = signal::ctrl_c().await {
                error!(?error, "Couldn't listen for shutdown signal.");
            }
        }
        shutdown_signal_.notify_waiters();
    });

    let (pub_tx, pub_rx) = unbounded_channel();

    let config = read_to_string(&args.config)
        .map_err(|error| {
            error!(
                ?error,
                config = args.config,
                "An error occurred while reading the configuration file."
            );
        })
        .unwrap();

    let mut connector: Box<dyn Connector> = match args.connector.as_str() {
        "binancefutures" => {
            let mut connector = BinanceFutures::build_from(&config)
                .map_err(|error| {
                    error!(?error, "Couldn't build the BinanceFutures connector.");
                })
                .unwrap();
            connector.run(pub_tx.clone());
            Box::new(connector)
        }
        "bybit" => {
            let mut connector = Bybit::build_from(&config)
                .map_err(|error| {
                    error!(?error, "Couldn't build the Bybit connector.");
                })
                .unwrap();
            connector.run(pub_tx.clone());
            Box::new(connector)
        }
        "binancespot" => {
            let mut connector = BinanceSpot::build_from(&config)
                .map_err(|error| {
                    error!(?error, "Couldn't build the Bybit connector.");
                })
                .unwrap();
            connector.run(pub_tx.clone());
            Box::new(connector)
        }
        connector => {
            error!(%connector, "This connector doesn't exist.");
            exit(1);
        }
    };

    let name = args.name.clone();
    let order_manager = connector.order_manager();
    let handle = thread::spawn(move || {
        let rt = Builder::new_current_thread().enable_all().build().unwrap();

        rt.block_on(async move {
            run_publish_task(&name, order_manager, pub_rx, shutdown_signal)
                .await
                .map_err(|error: ChannelError| {
                    error!(
                        ?error,
                        "An error occurred while sending a live event to the bots."
                    );
                })
                .unwrap();
        });
    });

    let name = args.name;
    run_receive_task(&name, pub_tx, &mut connector)
        .map_err(|error| {
            error!(
                ?error,
                "An error occurred while receiving a request from the bots."
            );
        })
        .unwrap();
    let _ = handle.join();
}
